import{_ as e,o,c as r,ag as a}from"./chunks/framework.OsDJF_Ea.js";const n="/docs/modules/chord-generator.png",g=JSON.parse('{"title":"Chord Generator","description":"","frontmatter":{},"headers":[],"relativePath":"modules/chord-generator.md","filePath":"modules/chord-generator.md"}'),i={name:"modules/chord-generator.md"};function c(s,t,d,h,l,p){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="chord-generator" tabindex="-1">Chord Generator <a class="header-anchor" href="#chord-generator" aria-label="Permalink to &quot;Chord Generator&quot;">​</a></h1><p><strong>Category:</strong> MIDI Effects</p><p>Takes a single pitch CV (from MIDIIn, Sequencer, PiezoInputSCM, Scale, etc.) and emits four pitch CVs corresponding to the notes of a chord built on that root. Feed each output into its own Oscillator for a discrete harmoniser, OR wire the <code>chord</code> output to a PolyOscillator&#39;s <code>note</code> input for a one-cable poly voice — <code>output_channel</code> controls which MIDI channel ChordGenerator emits on, match it on PolyOscillator to receive.</p><img src="'+n+'" alt="chord-generator module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>in</strong></td><td>Root pitch (/48-encoded pitch CV). Everything else is derived from this.</td></tr><tr><td><strong>trigger</strong></td><td>Note trigger for the <code>chord</code> MIDI output. Rising edge = chord-on, falling edge = chord-off. Accepts any gate/trigger signal (PiezoInputSCM&#39;s <code>trigger</code> output is actually a gate with hysteresis, MIDIIn&#39;s <code>gate</code>, Button&#39;s press, Clock, LFO &gt; 0.5, etc.). If unconnected, ChordGenerator acts as a continuous harmoniser and re-emits only when the root pitch changes.</td></tr><tr><td><strong>velocity</strong></td><td>Velocity CV (0-1 → 1-127) for the <code>chord</code> MIDI output. Patch a piezo envelope here for dynamic chord voicings. Falls back to the velocity param if unconnected.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>pitch1</strong></td><td>Voice 1 pitch CV (root in root position, or shifted up an octave when inversion &gt; 0).</td></tr><tr><td><strong>pitch2</strong></td><td>Voice 2 pitch CV (third interval — major/minor/sus by chord type).</td></tr><tr><td><strong>pitch3</strong></td><td>Voice 3 pitch CV (fifth interval — perfect / diminished / augmented by chord type).</td></tr><tr><td><strong>pitch4</strong></td><td>Voice 4 pitch CV (seventh or octave — triads use +12 so all four voices stay active; 7th-family chord types use the actual 7th interval).</td></tr><tr><td><strong>chord</strong></td><td>Poly MIDI output to PolyOscillator. Set <code>output_channel</code> &gt; 0 to enable — the cable itself carries the root pitch CV for documentation, but the actual poly note data flows via the firmware&#39;s global MIDI event queue and is read by PolyOsc&#39;s voice allocator.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Legacy port names <code>root/third/fifth/seventh</code> still work on the firmware side for old patches. For an in-key harmoniser on a noisy pitch source: PiezoInputSCM.pitch → Scale(quantise) → ChordGenerator → 4×Scale(quantise) → 4×Oscillator. For one-cable poly: ChordGenerator.chord → PolyOscillator.note, set output_channel on ChordGenerator and matching channel on PolyOsc. Gate input from PiezoInputSCM lets the chord track attack/release of the physical strike.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const m=e(i,[["render",c]]);export{g as __pageData,m as default};
